const items = $input.all();

return items.map((item) => {

    // Get the full generated text
    const fullText = item.json.content[0].text;

    // Extract Subject
    const subject = fullText
        .split('|||SUBJECT|||')[1]
        .split('|||BODY|||')[0]
        .trim();

    // Extract Body
    const body = fullText
        .split('|||BODY|||')[1]
        .trim();

    // Return structured output
    return {
        json: {
            ...item.json,
            subject: subject,
            body: body
        }
    };
});
